for (const item of items) {
  // Создаем массив объектов для каждой биржи
  // Название биржи должно соответствовать префиксу в полях
  const exchanges = [
    { name: 'MEXC', buyPrice: parseFloat(item.json.MEXC_BUY_PRICE), sellPrice: parseFloat(item.json.MEXC_SELL_PRICE) },
    { name: 'Bybit', buyPrice: parseFloat(item.json.BYBIT_BUY_PRICE), sellPrice: parseFloat(item.json.BYBIT_SELL_PRICE) },
    { name: 'OKX', buyPrice: parseFloat(item.json.OKX_BUY_PRICE), sellPrice: parseFloat(item.json.OKX_SELL_PRICE) },
    { name: 'HTX', buyPrice: parseFloat(item.json.HTX_BUY_PRICE), sellPrice: parseFloat(item.json.HTX_SELL_PRICE) },
    { name: 'Gate', buyPrice: parseFloat(item.json.GATE_BUY_PRICE), sellPrice: parseFloat(item.json.GATE_SELL_PRICE) },
    // Добавляйте новые биржи здесь в таком же формате:
    // { name: 'ИМЯ_БИРЖИ', buyPrice: parseFloat(item.json.ИМЯ_БИРЖИ_BUY_PRICE), sellPrice: parseFloat(item.json.ИМЯ_БИРЖИ_SELL_PRICE) },
  ];

  // Фильтруем только те биржи, у которых есть актуальные данные
  const validExchanges = exchanges.filter(ex => ex.buyPrice && ex.sellPrice && ex.buyPrice > 0 && ex.sellPrice > 0);

  // Если данных меньше, чем с двух бирж, пропускаем
  if (validExchanges.length < 2) {
    item.json.spread = 0;
    continue;
  }

  // Находим лучшую цену покупки и продажи
  let bestBuy = { price: Infinity, exchange: '' };
  let bestSell = { price: 0, exchange: '' };

  for (const ex of validExchanges) {
    if (ex.buyPrice < bestBuy.price) {
      bestBuy.price = ex.buyPrice;
      bestBuy.exchange = ex.name;
    }
    if (ex.sellPrice > bestSell.price) {
      bestSell.price = ex.sellPrice;
      bestSell.exchange = ex.name;
    }
  }

  // Рассчитываем спред
  const spread = ((bestSell.price - bestBuy.price) / bestBuy.price) * 100;

  // !!! НОВАЯ ПРОВЕРКА: отсекаем спреды больше 50% и отрицательные
  if (spread > 50 || spread < 0) {
    item.json.spread = 0;
  } else {
    item.json.spread = spread;
  }

  // Сохраняем результат в элементе
  item.json.bestBuyPrice = bestBuy.price;
  item.json.bestSellPrice = bestSell.price;
  item.json.bestBuyExchangeName = bestBuy.exchange;
  item.json.bestSellExchangeName = bestSell.exchange;
}

return items;

// Этот код берет данные о спреде и передает их дальше
return items.map(item => ({
  json: {
    coin_name: item.json.COIN.replace('USDT', ''),
    original_data: item.json
  }
}));

const finalResults = [];

// 1. Группируем результаты запроса PostgreSQL по монете и сети
const coinNetworkMap = {};
for (const item of items) {
    // Нормализация: убеждаемся, что работаем с чистым объектом
    const json = item.json || item;

    const coinName = json.coin_name;
    const chain = json.chain;
    const exchange = json.exchange;

    if (!coinName || !chain || !exchange) continue; // Пропускаем неполные данные

    if (!coinNetworkMap[coinName]) {
        coinNetworkMap[coinName] = {};
    }
    if (!coinNetworkMap[coinName][chain]) {
        // Используем Set для хранения уникальных бирж для каждой связки (монета + сеть)
        coinNetworkMap[coinName][chain] = new Set();
    }
    coinNetworkMap[coinName][chain].add(exchange);
}

// 2. Итерируем по сгруппированным данным, чтобы найти совпадающие сети
for (const coinName in coinNetworkMap) {
    const networks = coinNetworkMap[coinName];

    // Временный массив для хранения всех найденных общих сетей для данной монеты
    const foundCommonChains = []; 
    const allExchangesForCoin = new Set(); // Все биржи, где найдены общие сети

    for (const chain in networks) {
        const currentExchanges = Array.from(networks[chain]);

        // Проверяем, есть ли хотя бы две биржи в одной сети (это и есть "совпадение")
        if (currentExchanges.length > 1) {
            // Сохраняем информацию о совпадении для дальнейшего размножения
            foundCommonChains.push({
                chain: chain,
                exchanges: currentExchanges
            });
            // Добавляем все эти биржи в общий Set для монеты
            currentExchanges.forEach(ex => allExchangesForCoin.add(ex));
        }
    }

    // 3. --- Ключевое ИЗМЕНЕНИЕ: Формируем отдельный объект для каждой совпадающей сети ---
    if (foundCommonChains.length > 0) {
        const exchangesString = Array.from(allExchangesForCoin).join(', ');

        for (const commonChainInfo of foundCommonChains) {
             finalResults.push({
                json: {
                    // Добавляем USDT к названию монеты
                    coin: coinName + 'USDT',
                    // !!! Записываем ТОЛЬКО одну сеть на объект !!!
                    commonChains: commonChainInfo.chain, 
                    // Список всех бирж, где нашлась эта монета с общими сетями
                    exchanges: exchangesString, 
                    // Дополнительное поле: список бирж, которые совпали ИМЕННО по этой сети
                    exchanges_on_chain: commonChainInfo.exchanges.join(', ') 
                }
            });
        }
    }
}

// 4. Проверка и вывод сообщения, если совпадений не найдено
if (finalResults.length === 0) {
    return [{
        json: {
            message: 'Не найдено ни одной монеты с совпадающими сетями на разных биржах.'
        }
    }];
}

return finalResults;

