        // Проверяем, есть ли хотя бы две биржи в одной сети (это и есть "совпадение")
        if (currentExchanges.length > 1) {
            // Сохраняем информацию о совпадении для дальнейшего размножения
            foundCommonChains.push({
                chain: chain,
                exchanges: currentExchanges
            });
            // Добавляем все эти биржи в общий Set для монеты
            currentExchanges.forEach(ex => allExchangesForCoin.add(ex));
        }
    }

    // 3. --- Ключевое ИЗМЕНЕНИЕ: Формируем отдельный объект для каждой совпадающей сети ---
    if (foundCommonChains.length > 0) {
        const exchangesString = Array.from(allExchangesForCoin).join(', ');

        for (const commonChainInfo of foundCommonChains) {
             finalResults.push({
                json: {
                    // Добавляем USDT к названию монеты
                    coin: coinName + 'USDT',
                    // !!! Записываем ТОЛЬКО одну сеть на объект !!!
                    commonChains: commonChainInfo.chain, 
                    // Список всех бирж, где нашлась эта монета с общими сетями
                    exchanges: exchangesString, 
                    // Дополнительное поле: список бирж, которые совпали ИМЕННО по этой сети
                    exchanges_on_chain: commonChainInfo.exchanges.join(', ') 
                }
            });
        }
    }
}

