}

// Определяем размер каждой половины
const halfSize = Math.floor(totalItems / 2);

// Цикл проходит только по ПЕРВОЙ половине
for (let i = 0; i < halfSize; i++) {

    // Элемент из первой половины (например, анализ Покупки)
    const itemA = items[i];
    const jsonA = itemA.json || itemA;

    // Соответствующий элемент из ВТОРОЙ половины (например, анализ Продажи)
    const itemB = items[i + halfSize];
    const jsonB = itemB.json || itemB;

    // Создаем новый объединенный объект
    // Поля из jsonB перезаписывают поля из jsonA, если они совпадают
    const mergedJson = {
        ...jsonA,
        ...jsonB
    };

    // Добавляем объединенный объект в финальный массив
    finalItems.push({ json: mergedJson });
}

