// Целевая биржа для этого запроса
const TARGET_EXCHANGE = 'BINGX'; 

for (const item of items) {
    const json = item.json;

    // Получаем целевую биржу из арбитражного анализа
    const targetExchange = json.bestSellExchangeName; 

    // 1. Фильтр: Проверяем, что целевая биржа - BingX
    if (targetExchange && targetExchange.toUpperCase() !== TARGET_EXCHANGE) {
        // Пропускаем все, что не BingX
        continue;
    }

    // Проверка наличия символа монеты
    const coin = json.coin_name || json.COIN;
    if (!coin) {
        continue;
    }

    // Базовый URL BingX API
    const baseUrl = 'https://open-api.bingx.com';

    // 2. --- КЛЮЧЕВОЕ ИЗМЕНЕНИЕ: ФОРМИРОВАНИЕ ПАРЫ С ДЕФИСОМ ---

    // Монета в верхнем регистре (например, BTCUSDT)
    let symbolUpper = coin.toUpperCase();

    // Логика:
    // Если строка заканчивается на 'USDT' (самый распространенный случай)
    if (symbolUpper.endsWith('USDT')) {
        // Удаляем USDT и вставляем '-USDT' (BTCUSDT -> BTC-USDT)
        symbolUpper = symbolUpper.replace('USDT', '-USDT');
    } else if (symbolUpper.endsWith('BUSD')) {
        // Дополнительная проверка на BUSD, если применимо
        symbolUpper = symbolUpper.replace('BUSD', '-BUSD');
    }
    // Если символ уже содержит дефис (например, BTC-USDT), он останется неизменным.

    const symbol = symbolUpper;
    // -------------------------------------------------------------

    // BingX использует публичный эндпоинт /openApi/spot/v1/market/depth
    // Параметры BingX: symbol (верхний регистр с дефисом), limit (количество уровней)
    const endpoint = `/openApi/spot/v1/market/depth?symbol=${symbol}&limit=20`; 


    // Передаем URL и оригинальные данные дальше
    processedItems.push({
        json: {
            ...json, 
            // !!! НОВЫЕ ПОЛЯ для запроса стакана
            orderBookUrl: `${baseUrl}${endpoint}`,
            orderBookExchange: TARGET_EXCHANGE
        }
    });
}

return processedItems;

