const DEFAULT_MAX_VOLUME = 100000000;
const REQUIRED_SPREAD_PERC = 0; // минимальный спред, %

const finalItems = [];

// Рекурсивный поиск asks где бы они ни были
function findAsks(obj) {
  if (!obj || typeof obj !== "object") return [];
  if (Array.isArray(obj.asks)) return obj.asks;
  for (const key of Object.keys(obj)) {
    const val = obj[key];
    if (Array.isArray(val) && val.length && Array.isArray(val[0]) && val[0].length === 2) {
      // массив пар цен/количества
      return val;
    }
    if (typeof val === "object") {
      const found = findAsks(val);
      if (found.length) return found;
    }
  }
  return [];
}

for (const item of items) {
  const json = item.json || item;

  // === 1️⃣ Находим стакан ===
  const asks = findAsks(json);
  const bestSellPrice = Number(json.bestSellPrice) || 0;

  if (!asks.length || bestSellPrice <= 0) {
    json.status = "❌ asks не найдены";
    json.max_available_volume_buy = "0.00";
    json.position_base_coin = "0.00";
    json.lastAskPriceUsed = "0.00";
    finalItems.push({ json });
    continue;
  }

  // === 2️⃣ Анализ стакана ===
  let accumulatedQuoteVolume = 0;
  let totalBaseVolume = 0;
  let lastPrice = 0;

  for (const entry of asks) {
    const price = Number(entry[0]);
    const qty = Number(entry[1]);
    if (!price || !qty) continue;

    const levelVolumeUSDT = price * qty;
    const potentialSpread = (bestSellPrice - price) / price;

    if (potentialSpread < REQUIRED_SPREAD_PERC / 100) continue;

    if (accumulatedQuoteVolume + levelVolumeUSDT > DEFAULT_MAX_VOLUME) {
      const remainUSDT = DEFAULT_MAX_VOLUME - accumulatedQuoteVolume;
      const remainBase = remainUSDT / price;
      totalBaseVolume += remainBase;
      accumulatedQuoteVolume = DEFAULT_MAX_VOLUME;
      lastPrice = price;
      break;
    }

    accumulatedQuoteVolume += levelVolumeUSDT;
    totalBaseVolume += qty;
    lastPrice = price;
  }

  // === 3️⃣ Результат ===
  json.status = accumulatedQuoteVolume > 0 ? "✅ OK" : "⚠️ объём не найден";
  json.max_available_volume_buy = accumulatedQuoteVolume.toFixed(2);
  json.position_base_coin = totalBaseVolume.toFixed(4);
  json.lastAskPriceUsed = lastPrice ? lastPrice.toFixed(6) : "0.000000";

  finalItems.push({ json });
}

return finalItems;

